import{_ as n,o as e,c as s,ag as l}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"架构概览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1774182280000}'),t={name:"guide/architecture.md"};function i(p,a,d,o,c,h){return e(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><h2 id="整体架构" tabindex="-1">整体架构 <a class="header-anchor" href="#整体架构" aria-label="Permalink to &quot;整体架构&quot;">​</a></h2><p>Clawline 采用 <strong>Relay 中转架构</strong>，三个组件各司其职：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    公网 (Relay)                       │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │            Relay Gateway                      │   │</span></span>
<span class="line"><span>│  │                                               │   │</span></span>
<span class="line"><span>│  │  /client  ← 客户端 WebSocket 连接             │   │</span></span>
<span class="line"><span>│  │  /backend ← Agent 后端 WebSocket 连接         │   │</span></span>
<span class="line"><span>│  │                                               │   │</span></span>
<span class="line"><span>│  │  ┌─────────┐  ┌─────────┐  ┌─────────┐      │   │</span></span>
<span class="line"><span>│  │  │Channel A│  │Channel B│  │Channel C│      │   │</span></span>
<span class="line"><span>│  │  │(鉴权配置)│  │(鉴权配置)│  │(鉴权配置)│      │   │</span></span>
<span class="line"><span>│  │  └─────────┘  └─────────┘  └─────────┘      │   │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│          ↑                           ↑               │</span></span>
<span class="line"><span>│          │ wss://                     │ wss://        │</span></span>
<span class="line"><span>│          │                           │               │</span></span>
<span class="line"><span>│  ┌───────┴───────┐          ┌───────┴──────────┐   │</span></span>
<span class="line"><span>│  │  Client Web   │          │  OpenClaw Node   │   │</span></span>
<span class="line"><span>│  │  (用户浏览器)  │          │  + Channel Plugin│   │</span></span>
<span class="line"><span>│  │               │          │  (可在内网)       │   │</span></span>
<span class="line"><span>│  └───────────────┘          └──────────────────┘   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="连接方向" tabindex="-1">连接方向 <a class="header-anchor" href="#连接方向" aria-label="Permalink to &quot;连接方向&quot;">​</a></h2><p>这是 Clawline 和传统 Webhook 方案的<strong>根本区别</strong>：</p><table tabindex="0"><thead><tr><th></th><th>传统 Webhook</th><th>Clawline Relay</th></tr></thead><tbody><tr><td>连接发起方</td><td>平台 → Agent（回调）</td><td>Agent → Relay（主动连出）</td></tr><tr><td>Agent 网络要求</td><td>必须有公网 IP</td><td>只需能访问 Relay 地址</td></tr><tr><td>防火墙</td><td>必须开入站端口</td><td>仅出站连接</td></tr><tr><td>内网部署</td><td>需要 ngrok 等穿透</td><td>原生支持</td></tr></tbody></table><h2 id="消息流转" tabindex="-1">消息流转 <a class="header-anchor" href="#消息流转" aria-label="Permalink to &quot;消息流转&quot;">​</a></h2><h3 id="用户发送消息" tabindex="-1">用户发送消息 <a class="header-anchor" href="#用户发送消息" aria-label="Permalink to &quot;用户发送消息&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Web → Relay (/client) → 路由到对应 Channel → Relay (/backend) → Channel Plugin → OpenClaw Agent</span></span></code></pre></div><ol><li>Client Web 通过 WebSocket 发送 <code>message.receive</code> 事件</li><li>Relay 根据 <code>channelId</code> 找到对应后端连接</li><li>Channel Plugin 接收消息，转换为 OpenClaw 内部格式</li><li>Agent 处理消息</li></ol><h3 id="agent-回复" tabindex="-1">Agent 回复 <a class="header-anchor" href="#agent-回复" aria-label="Permalink to &quot;Agent 回复&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenClaw Agent → Channel Plugin → Relay (/backend) → 路由到用户连接 → Relay (/client) → Client Web</span></span></code></pre></div><ol><li>Agent 生成回复（支持流式）</li><li>Channel Plugin 发送 <code>text.delta</code>（流式）或 <code>message.send</code>（完整）</li><li>Relay 根据 <code>connectionId</code> 路由到对应客户端</li><li>Client Web 实时渲染</li></ol><h3 id="文件上传" tabindex="-1">文件上传 <a class="header-anchor" href="#文件上传" aria-label="Permalink to &quot;文件上传&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Web → Relay /api/media/upload → 返回 URL → 在消息中引用 URL</span></span></code></pre></div><ul><li>小文件（&lt;100KB）：Base64 内嵌在消息中</li><li>大文件（≥100KB）：先上传到 Relay，消息中携带 URL</li><li>鉴权：Channel User Token 或 JWT</li></ul><h2 id="多节点" tabindex="-1">多节点 <a class="header-anchor" href="#多节点" aria-label="Permalink to &quot;多节点&quot;">​</a></h2><p>一个 Relay 可以管理多个 Channel（Agent 节点）：</p><ul><li>每个 Channel 有独立的 ID、Secret、用户列表</li><li>多个 Agent 节点可以同时连接</li><li>客户端通过 <code>channelId</code> 参数选择连接哪个 Agent</li></ul><p>适用场景：一个 Relay 对接多个业务场景的 Agent。</p><h2 id="鉴权体系" tabindex="-1">鉴权体系 <a class="header-anchor" href="#鉴权体系" aria-label="Permalink to &quot;鉴权体系&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Web → token=xxx → Relay 校验 → 通过后建立连接 → Plugin 信任 Relay 下发的身份</span></span></code></pre></div><ul><li>Relay 管理 Channel 用户列表（token + senderId）</li><li>也支持 Logto JWT 认证</li><li>Channel Plugin 信任 Relay 的鉴权结果，不再二次校验</li><li>Admin API 使用独立的 API Key 或 Logto JWT</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./quickstart.html">快速开始</a> — 动手跑起来</li></ul>`,26)])])}const g=n(t,[["render",i]]);export{u as __pageData,g as default};
